import { isNull } from "./TypeUtils.js";
export class OptionLoader {
    load(data) {
        if (isNull(data)) {
            return;
        }
        this.doLoad(data);
    }
}
export function loadOptions(options, ...sourceOptionsArr) {
    for (const sourceOptions of sourceOptionsArr) {
        options.load(sourceOptions);
    }
}
